  BT_DATA.quizzes.push({"id":"gen-z-slang-trivia","slug":"gen-z-slang-trivia","title":"Do You Actually Know Gen Z Slang?","category":"trivia","type":"trivia","image":"https://images.unsplash.com/photo-1611605698335-8b1569810432","description":"Think you've got the vocab of a true terminally-online icon? This 25-question gauntlet runs through the slang that actually rules your group chat, from rizz to delulu to bussin. One right answer each, no cap.","tagline":"Prove your group chat fluency in 25 questions, no cap.","estMinutes":6,"takenCount":18315,"results":[{"key":"fluent","minPct":85,"title":"Certified Slang Scholar","emoji":"🧠","image":"https://loremflickr.com/800/600/scholar?lock=59879","description":"You don't just speak the language, you set the trends. Your rizz is academic and your vocab is unmatched.","share":"I scored Certified Slang Scholar on the Gen Z slang quiz. My vocab literally ate. Can you beat me?"},{"key":"fluent_ish","minPct":60,"title":"Fluent in the Group Chat","emoji":"💬","image":"https://loremflickr.com/800/600/chat?lock=47177","description":"You hold your own in any comment section and rarely get lost. A few terms still mog you, but you're solid.","share":"I'm officially Fluent in the Group Chat. Bet you can't out-slang me on this quiz."},{"key":"learning","minPct":35,"title":"Lowkey Still Learning","emoji":"📚","image":"https://loremflickr.com/800/600/learning?lock=36031","description":"You know the hits but the deep cuts catch you off guard. A little more scrolling and you'll be unstoppable.","share":"I'm Lowkey Still Learning the slang. Take this quiz and tell me you did better, no cap."},{"key":"npc","minPct":0,"title":"Certified NPC","emoji":"🤖","image":"https://loremflickr.com/800/600/books,vintage?lock=72012","description":"The slang is giving full mystery to you right now. Time to touch some TikTok and run it back.","share":"This quiz fully exposed me as a Certified NPC. Help. Can you actually pass it?"}],"questions":[{"q":"What does \"rizz\" mean?","options":[{"text":"Charm or the ability to attract a romantic interest","correct":true},{"text":"A sudden burst of anger","correct":false},{"text":"Money you make from a side hustle","correct":false},{"text":"A perfectly timed comeback in an argument","correct":false}]},{"q":"If someone is \"delulu,\" they are being what?","options":[{"text":"Delusional or holding unrealistic beliefs","correct":true},{"text":"Extremely tired and burnt out","correct":false},{"text":"Overly dramatic about small things","correct":false},{"text":"Secretly jealous of a friend","correct":false}]},{"q":"When a performance or outfit \"ate,\" what does that mean?","options":[{"text":"It was done flawlessly and impressed everyone","correct":true},{"text":"It was a total disaster","correct":false},{"text":"It was boring and forgettable","correct":false},{"text":"It copied someone else's idea","correct":false}]},{"q":"Calling a movie \"mid\" means it was what?","options":[{"text":"Mediocre or average, nothing special","correct":true},{"text":"Surprisingly amazing","correct":false},{"text":"Way too long","correct":false},{"text":"Confusing and hard to follow","correct":false}]},{"q":"What is \"the ick\"?","options":[{"text":"A sudden feeling of disgust or being turned off by someone","correct":true},{"text":"A wave of nostalgia for the past","correct":false},{"text":"An inside joke shared by close friends","correct":false},{"text":"The feeling of missing out on plans","correct":false}]},{"q":"When you tell someone they \"slay,\" you mean they did what?","options":[{"text":"Looked amazing or did something impressively well","correct":true},{"text":"Made a careless mistake","correct":false},{"text":"Showed up late again","correct":false},{"text":"Started unnecessary drama","correct":false}]},{"q":"In slang, what does \"no cap\" mean?","options":[{"text":"For real, no lie, being totally honest","correct":true},{"text":"Without any limits or rules","correct":false},{"text":"I disagree completely","correct":false},{"text":"Take it easy, relax","correct":false}]},{"q":"If food is \"bussin,\" how is it?","options":[{"text":"Extremely good and tasty","correct":true},{"text":"Overpriced for what it is","correct":false},{"text":"Spicy enough to hurt","correct":false},{"text":"Cold and disappointing","correct":false}]},{"q":"Describing something as \"sus\" means it is what?","options":[{"text":"Suspicious or shady","correct":true},{"text":"Surprisingly good","correct":false},{"text":"Really expensive","correct":false},{"text":"Old and outdated","correct":false}]},{"q":"If someone is \"capping,\" what are they doing?","options":[{"text":"Lying or exaggerating","correct":true},{"text":"Bragging about money","correct":false},{"text":"Giving up on a plan","correct":false},{"text":"Ending a conversation early","correct":false}]},{"q":"What does it mean to call someone a \"simp\"?","options":[{"text":"Someone doing way too much to win another person's affection","correct":true},{"text":"Someone who is very lazy","correct":false},{"text":"Someone who copies other people's style","correct":false},{"text":"Someone who is rich and shows it off","correct":false}]},{"q":"A \"glow up\" refers to what?","options":[{"text":"A major transformation in appearance, style, or confidence","correct":true},{"text":"A sudden mood swing","correct":false},{"text":"Getting a lot of likes on a post","correct":false},{"text":"Staying up all night","correct":false}]},{"q":"To \"flex\" means to do what?","options":[{"text":"Show off something you have or did","correct":true},{"text":"Change your mind at the last minute","correct":false},{"text":"Avoid answering a question","correct":false},{"text":"Apologize without meaning it","correct":false}]},{"q":"If you \"stan\" someone, you are what?","options":[{"text":"A devoted, enthusiastic fan of them","correct":true},{"text":"Annoyed by them","correct":false},{"text":"Pretending to like them","correct":false},{"text":"Competing against them","correct":false}]},{"q":"\"Ghosting\" someone means what?","options":[{"text":"Suddenly cutting off all contact with no explanation","correct":true},{"text":"Secretly following their posts","correct":false},{"text":"Copying everything they do","correct":false},{"text":"Scaring them as a prank","correct":false}]},{"q":"When someone replies \"bet,\" what do they usually mean?","options":[{"text":"Okay, sounds good, I'm down","correct":true},{"text":"I doubt that will happen","correct":false},{"text":"That costs too much","correct":false},{"text":"Prove it to me","correct":false}]},{"q":"If someone is \"salty,\" they are feeling what?","options":[{"text":"Bitter, annoyed, or upset","correct":true},{"text":"Calm and relaxed","correct":false},{"text":"Proud of themselves","correct":false},{"text":"Confused about something","correct":false}]},{"q":"What is an \"NPC\" when used to describe a person?","options":[{"text":"Someone seen as basic, boring, or going through the motions like a background character","correct":true},{"text":"Someone who is always the center of attention","correct":false},{"text":"Someone brand new to a friend group","correct":false},{"text":"Someone who is extremely competitive","correct":false}]},{"q":"\"Menty b\" is short for what?","options":[{"text":"A mental breakdown","correct":true},{"text":"A mentor or guide","correct":false},{"text":"A minor inconvenience","correct":false},{"text":"A mean comment","correct":false}]},{"q":"What does \"looksmaxxing\" refer to?","options":[{"text":"Maximizing your appearance through grooming, fitness, and style","correct":true},{"text":"Taking tons of selfies in one session","correct":false},{"text":"Buying expensive designer clothes","correct":false},{"text":"Copying a celebrity's exact look","correct":false}]},{"q":"If something is \"cheugy,\" it is what?","options":[{"text":"Outdated or trying too hard to be trendy","correct":true},{"text":"Cutting-edge and fashionable","correct":false},{"text":"Cheap but surprisingly good","correct":false},{"text":"Overly serious or formal","correct":false}]},{"q":"Telling someone to \"touch grass\" means what?","options":[{"text":"Go outside and log off, you're too online","correct":true},{"text":"Calm down and stop yelling","correct":false},{"text":"Get back to work","correct":false},{"text":"Try something brand new","correct":false}]},{"q":"To \"gatekeep\" means to do what?","options":[{"text":"Withhold information to keep something exclusive","correct":true},{"text":"Welcome new people into a group","correct":false},{"text":"Share a secret with everyone","correct":false},{"text":"Guard your phone from snoopers","correct":false}]},{"q":"If something is \"living rent free\" in your head, it means what?","options":[{"text":"You can't stop thinking about it even though you want to","correct":true},{"text":"It costs you nothing to enjoy","correct":false},{"text":"You forgot about it completely","correct":false},{"text":"It makes you a lot of money","correct":false}]},{"q":"A \"beige flag\" in a relationship is what?","options":[{"text":"A trait that is neither good nor bad, just boring or quirky","correct":true},{"text":"A serious dealbreaker you should run from","correct":false},{"text":"A clear sign someone is perfect for you","correct":false},{"text":"A warning that someone is lying","correct":false}]}]});
  BT_DATA.quizzes.push({"id":"random-knowledge-trivia","slug":"random-knowledge-trivia","title":"The Random Knowledge Quiz","category":"trivia","type":"trivia","image":"https://images.unsplash.com/photo-1532012197267-da84d127e765","description":"25 genuinely interesting 'huh, neat' facts about science, animals, food, space, and the world. All verified true. How many will catch you off guard?","tagline":"The trivia that makes you go 'wait, WHAT' at 2am.","estMinutes":6,"takenCount":12470,"results":[{"key":"galaxy-brain","minPct":85,"title":"Certified Galaxy Brain","emoji":"🧠","image":"https://loremflickr.com/800/600/brain?lock=10827","description":"You are a walking pub-quiz cheat code. Random facts just live rent-free in your head and you nailed almost all of them.","share":"I got Certified Galaxy Brain on the Random Knowledge Quiz. My useless facts are not so useless now huh"},{"key":"fact-collector","minPct":60,"title":"Fun Fact Collector","emoji":"🦉","image":"https://loremflickr.com/800/600/collector?lock=1374","description":"You know way more weird stuff than the average person and it shows. A few facts got you, but you held it down.","share":"Fun Fact Collector on the Random Knowledge Quiz. I literally know things. Beat my score"},{"key":"curious-cat","minPct":35,"title":"Curious Cat","emoji":"🐈","image":"https://loremflickr.com/800/600/books,vintage?lock=88347","description":"You got a solid chunk right and probably said 'no way' out loud a few times. The vibes and the curiosity are immaculate.","share":"Curious Cat on the Random Knowledge Quiz. Learned some chaos, no regrets"},{"key":"blissfully-unaware","minPct":0,"title":"Blissfully Unaware","emoji":"🫠","image":"https://loremflickr.com/800/600/unaware?lock=55815","description":"The facts humbled you, but honestly that means every one was a brand new plot twist. Run it back and flex next time.","share":"Blissfully Unaware on the Random Knowledge Quiz. The facts ATE me. Can you do better?"}],"questions":[{"q":"How many hearts does an octopus have?","options":[{"text":"Three","correct":true},{"text":"One","correct":false},{"text":"Two","correct":false},{"text":"Five","correct":false}]},{"q":"Octopus blood is blue. What makes it that color?","options":[{"text":"A copper-based molecule called hemocyanin","correct":true},{"text":"Extra iron in their blood","correct":false},{"text":"Blue pigment from the algae they eat","correct":false},{"text":"A reaction with cold seawater","correct":false}]},{"q":"Why does honey basically never spoil, with edible pots found in ancient Egyptian tombs?","options":[{"text":"Very low water content and acidity make it hostile to microbes","correct":true},{"text":"It contains a natural preservative similar to salt","correct":false},{"text":"The sugar slowly turns into alcohol that kills bacteria","correct":false},{"text":"Bees add a wax coating that seals out air","correct":false}]},{"q":"On which planet is a single day longer than its entire year?","options":[{"text":"Venus","correct":true},{"text":"Mercury","correct":false},{"text":"Mars","correct":false},{"text":"Neptune","correct":false}]},{"q":"Sharks have been around so long that they are older than which of these?","options":[{"text":"Trees","correct":true},{"text":"The Sun","correct":false},{"text":"The Moon","correct":false},{"text":"Water on Earth","correct":false}]},{"q":"Wombats are famous for producing poop in what unusual shape?","options":[{"text":"Cubes","correct":true},{"text":"Perfect spheres","correct":false},{"text":"Spirals","correct":false},{"text":"Stars","correct":false}]},{"q":"What surprising thing can sometimes happen with hot versus cold water, known as the Mpemba effect?","options":[{"text":"Hot water can sometimes freeze faster than cold water","correct":true},{"text":"Cold water always boils faster than hot water","correct":false},{"text":"Hot water weighs more than the same amount of cold water","correct":false},{"text":"Cold water glows faintly when poured","correct":false}]},{"q":"The Eiffel Tower changes size with the seasons. What does it do in summer heat?","options":[{"text":"Grows about 15 cm taller as the iron expands","correct":true},{"text":"Shrinks slightly as the iron softens","correct":false},{"text":"Tilts a full meter toward the sun","correct":false},{"text":"Stays exactly the same, the story is a myth","correct":false}]},{"q":"Botanically speaking, which of these actually counts as a berry?","options":[{"text":"Banana","correct":true},{"text":"Strawberry","correct":false},{"text":"Raspberry","correct":false},{"text":"Blackberry","correct":false}]},{"q":"Why is there no sound in the vacuum of space?","options":[{"text":"There are basically no particles to carry the sound waves","correct":true},{"text":"Space is too cold for sound to exist","correct":false},{"text":"Sound gets pulled apart by gravity","correct":false},{"text":"The lack of light blocks sound from forming","correct":false}]},{"q":"Flamingos are not born pink. Where does their color actually come from?","options":[{"text":"Pigments called carotenoids in the food they eat","correct":true},{"text":"Sunlight slowly tinting their feathers","correct":false},{"text":"A pink dye in the water of their habitats","correct":false},{"text":"Genes that switch on once they reach adulthood","correct":false}]},{"q":"Which two planets in our solar system have no moons at all?","options":[{"text":"Mercury and Venus","correct":true},{"text":"Mars and Mercury","correct":false},{"text":"Venus and Mars","correct":false},{"text":"Mercury and Neptune","correct":false}]},{"q":"Cashews grow in an unusual way. Where is the cashew attached?","options":[{"text":"Hanging beneath a fleshy 'cashew apple'","correct":true},{"text":"Inside a pod underground like peanuts","correct":false},{"text":"Clustered in cones like pine nuts","correct":false},{"text":"Wrapped inside large leaves on the branch","correct":false}]},{"q":"What is the playful collective noun for a group of flamingos?","options":[{"text":"A flamboyance","correct":true},{"text":"A glamour","correct":false},{"text":"A blush","correct":false},{"text":"A parade","correct":false}]},{"q":"The deepest known point in the ocean, the Challenger Deep, is located in which trench?","options":[{"text":"The Mariana Trench","correct":true},{"text":"The Puerto Rico Trench","correct":false},{"text":"The Java Trench","correct":false},{"text":"The Tonga Trench","correct":false}]},{"q":"Which animal has fingerprints so similar to ours that they are hard to tell apart under a microscope?","options":[{"text":"Koala","correct":true},{"text":"Chimpanzee","correct":false},{"text":"Raccoon","correct":false},{"text":"Gorilla","correct":false}]},{"q":"Despite floating in the sky, a typical fluffy cumulus cloud can weigh roughly how much?","options":[{"text":"Over a million pounds","correct":true},{"text":"About 50 pounds","correct":false},{"text":"Around 1,000 pounds","correct":false},{"text":"Almost nothing, basically weightless","correct":false}]},{"q":"What is surprisingly true about a starfish's body?","options":[{"text":"It has no brain and no blood at all","correct":true},{"text":"It has three tiny hearts","correct":false},{"text":"It breathes through a single lung","correct":false},{"text":"It has a backbone like a fish","correct":false}]},{"q":"Cleopatra lived closer in time to which event than to the building of the Great Pyramid of Giza?","options":[{"text":"The Apollo 11 moon landing","correct":true},{"text":"The fall of the Roman Empire","correct":false},{"text":"The birth of Julius Caesar","correct":false},{"text":"The invention of paper","correct":false}]},{"q":"Botanically, peanuts are not actually nuts. What are they?","options":[{"text":"Legumes, related to beans and lentils","correct":true},{"text":"Seeds of a type of grass","correct":false},{"text":"Dried berries","correct":false},{"text":"Tubers, like small potatoes","correct":false}]},{"q":"Which is the hottest planet in our solar system?","options":[{"text":"Venus","correct":true},{"text":"Mercury","correct":false},{"text":"Mars","correct":false},{"text":"Jupiter","correct":false}]},{"q":"Pound for pound, how does spider silk compare to steel?","options":[{"text":"It is stronger than steel of the same weight","correct":true},{"text":"It is far weaker than any metal","correct":false},{"text":"It is roughly as strong as wet paper","correct":false},{"text":"It is stronger only when frozen","correct":false}]},{"q":"A US Supreme Court case once ruled on the tomato. What did it decide for tariff purposes?","options":[{"text":"It is legally a vegetable, even though botanically it is a fruit","correct":true},{"text":"It is legally a fruit, matching its botany","correct":false},{"text":"It is both a fruit and a vegetable depending on the season","correct":false},{"text":"It is neither, and counts as a spice","correct":false}]},{"q":"A narwhal's iconic spiral 'horn' is actually what?","options":[{"text":"A tooth, specifically an elongated canine","correct":true},{"text":"A true horn made of keratin","correct":false},{"text":"A bony spike growing from the skull","correct":false},{"text":"A hardened section of cartilage","correct":false}]},{"q":"What is true about lightning's temperature?","options":[{"text":"It can briefly get hotter than the surface of the Sun","correct":true},{"text":"It is roughly the same temperature as boiling water","correct":false},{"text":"It is actually cold to the touch","correct":false},{"text":"It never gets hotter than a campfire","correct":false}]}]});
